scwin.f_PchsSellCls = function () {
  console.log("=== f_PchsSellCls(매입,매출 변경시)");
  if (lc_pchsSellCls.getValue() == "1") {
    // 매출
    console.log("   1: 매출");
    lc_deductCls.setSelectedIndex(0);
    $c.gus.cfDisableObjects($p, [lc_deductCls]);

    // btPrnt.style.display = "inline";
    // oz_popup.style.display = "none";
    // ja_oz_popup.style.display = "none";  // 자회사매입세금계산서발행

    btPrnt.show(""); // 레포트 버튼열 보임
    btn_oz_popup.hide(); // 매입세금계산서일괄발행 버튼 숨김
    btn_ja_oz_popup.hide(); // 자회사매입세금계산서발행 버튼 숨김

    console.log("==-==-== [" + lc_pchsSellCls.getValue() + "]  보임 (레포트 버튼열) 숨김 (매입세금계산서일괄발행, 자회사매입세금계산서발행)");
  } else {
    $c.gus.cfEnableObjects($p, [lc_deductCls]);

    // btPrnt.style.display = "none";
    btPrnt.hide(); // 레포트 버튼열 숨김

    if (scwin.vLoginCoCd == '024') {
      // 동화일때만 오픈
      console.log("==-==-== 자회사(024 동화) 일 때 - 자회사매입세금계산서발행 버튼 활성");
      // ja_oz_popup.style.display = "inline";  // 자회사매입세금계산서발행
      btn_ja_oz_popup.show("");
    } else {
      console.log("==-==-== 자회사(024 동화) 아닐 때 - 숨김 (자회사매입세금계산서발행)");
      // ja_oz_popup.style.display = "none";   // 자회사매입세금계산서발행
      btn_ja_oz_popup.hide();
    }

    // hades119	동원ENT(권정민), 811160	RPA봇 일 때 오픈
    if (scwin.userId == "hades119" || scwin.userId == "811160") {
      // oz_popup.style.display = "inline";
      btn_oz_popup.show(""); // 매입세금계산서일괄발행 활성

      console.log("==-==-== hades119, 811160 - 보임 (매입세금계산서일괄발행)");
    } else {
      if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
        // oz_popup.style.display = "none";
        btn_oz_popup.hide(); // 매입세금계산서일괄발행 비활성

        console.log("==-==-== hades119, 811160 아니고, 자회사 - 숨김 (매입세금계산서일괄발행)");
      } else {
        // oz_popup.style.display = "inline";
        btn_oz_popup.show(""); // 매입세금계산서일괄발행 활성

        console.log("==-==-== hades119, 811160 아니고, 자회사 아닐 때 - 보임 (매입세금계산서일괄발행)");
      }
    }
  }

  // 증빙구분변경시
  scwin.f_EvidClsCd();
};

//-------------------------------------------------------------------------
// 회계처리변경시
//-------------------------------------------------------------------------
scwin.f_PostYn = function () {
  console.log("=== f_PostYn (회계처리변경시 - 회계일자 활성/비활성)");
  if (lc_postYn.getValue() == "0") {
    ed_postDtSt.setValue("");
    ed_postDtEnd.setValue("");
    // 회계일자 비활성
    $c.gus.cfDisableObjects($p, [ed_postDtSt]);
    $c.gus.cfDisableObjects($p, [ed_postDtEnd]);
  } else {
    // 회계일자 활성
    $c.gus.cfEnableObjects($p, [ed_postDtSt]);
    $c.gus.cfEnableObjects($p, [ed_postDtEnd]);
  }
};

//-------------------------------------------------------------------------
