scwin.f_Retrieve = async function (e) {
  console.log("====== f_Retrieve ==================");

  // if (!cfValidate([ed_coCd,ed_spplyDtSt,ed_spplyDtEnd,ed_slipDtSt,ed_slipDtEnd,ed_postDtSt,ed_postDtEnd,ed_slipNo]))
  // let rtn1 = await $c.gus.cfValidate([ed_coCd,ed_spplyDtSt,ed_spplyDtEnd,ed_slipDtSt,ed_slipDtEnd,ed_postDtSt,ed_postDtEnd,ed_slipNo]);
  let rtn1 = await $c.gus.cfValidate($p, [ed_coCd, ed_spplyDtSt, ed_slipNo]);
  if (!rtn1) return false;
  if (!$c.gus.cfIsAfterDate($p, ed_spplyDtSt.getValue().trim(), ed_spplyDtEnd.getValue().trim())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ed_spplyDtSt.focus();
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_slipDtSt.getValue().trim(), ed_slipDtEnd.getValue().trim())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ed_slipDtSt.focus();
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_postDtSt.getValue().trim(), ed_postDtEnd.getValue().trim())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ed_postDtSt.focus();
    return false;
  }
  var date1 = ed_spplyDtSt.getValue().trim();
  var date2 = ed_spplyDtEnd.getValue().trim();
  var date3 = ed_slipDtSt.getValue().trim();
  var date4 = ed_slipDtEnd.getValue().trim();
  var date5 = ed_postDtSt.getValue().trim();
  var date6 = ed_postDtEnd.getValue().trim();
  if (ds_empNo.getTotalRow() > 0) {
    if (date1.substr(0, 4) <= "2013" || date2.substr(0, 4) >= "2019") {
      await $c.win.alert($p, "2014~2018년 이외의 조회 권한이 없습니다.");
      return false;
    }
    if (date3 != "" && date4 != "") {
      if (date3.substr(0, 4) <= "2013" || date4.substr(0, 4) >= "2019") {
        await $c.win.alert($p, "2014~2018년 이외의 조회 권한이 없습니다.");
        return false;
      }
    }
    if (date5 != "" && date6 != "") {
      if (date5.substr(0, 4) <= "2013" || date6.substr(0, 4) >= "2019") {
        await $c.win.alert($p, "2014~2018년 이외의 조회 권한이 없습니다.");
        return false;
      }
    }
  }
  if (ed_spplyDtSt.getValue().trim() < "20110101" && ed_spplyDtEnd.getValue().trim() > "20101231") {
    await $c.win.alert($p, "2010년도와 2011년도 자료는 동시에 조회할 수 없습니다.\n 따로 조회해주시기 바랍니다");
    return false;
  }

  // if(bSearch2.style.display=="none"){
  // 	bSearch2.style.display="";
  // }

  if (ed_bSearch2.getStyle("visibility") == "hidden") {
    // 현재 데이터 조회중입니다. 잠시만 기다려 주세요.
    ed_bSearch2.show(""); // 현재 데이터 조회중입니다. 잠시만 기다려 주세요.
  }
  scwin.txt_pageNumber = scwin.pageNumber;
  scwin.txt_quantityOfRows = scwin.quantityOfRows;

  // ds_search.UseChangeInfo = false;

  var strParam = {
    spplyDtSt: ed_spplyDtSt.getValue() // 계산서일자From
    ,
    spplyDtEnd: ed_spplyDtEnd.getValue() // 계산서일자To
    ,
    slipDtSt: ed_slipDtSt.getValue() // 전표작성일자From
    ,
    slipDtEnd: ed_slipDtEnd.getValue() // 전표작성일자To
    ,
    postDtSt: ed_postDtSt.getValue() // 회계일자From
    ,
    postDtEnd: ed_postDtEnd.getValue() // 회계일자To
    ,
    slipKndCd: ed_slipKndCd.getValue() // 전표종류코드
    ,
    slipKndNm: ed_slipKndNm.getValue() // 전표종류명
    ,
    drawAcctDeptCd: ed_drawAcctDeptCd.getValue() // 작성귀속부서코드
    ,
    drawAcctDeptNm: ed_drawAcctDeptNm.getValue() // 작성귀속부서명
    ,
    pchsSellCls: lc_pchsSellCls.getValue() // 매입매출구분
    ,
    evidClsCd: lc_evidClsCd.getValue() // 증빙구분코드
    ,
    deductCls: lc_deductCls.getValue() // 공제구분
    ,
    zeroTaxCls: lc_zeroTaxCls.getValue() // 영세율구분
    ,
    vatDeclarAcctDeptCd: ed_vatDeclarAcctDeptCd.getValue() // 부가세관리귀속부서
    ,
    vatDeclarAcctDeptNm: ed_vatDeclarAcctDeptNm.getValue() // 부가세신고귀속부서명
    ,
    crn: ed_crn.getValue() // 사업자등록번호
    ,
    crnNm: ed_crnNm.getValue() // 사업자등록번호명
    ,
    delYn: lc_delYn.getValue() // 삭제여부
    ,
    declarExceptYn: lc_declarExceptYn.getValue() // 신고제외여부
    ,
    postYn: lc_postYn.getValue() // 회계처리여부
    ,
    slipNo: ed_slipNo.getValue() // DEBIS전표번호
    ,
    drawEmpNo: ed_drawEmpNo.getValue() // 작성자사원번호
    ,
    coCd: ed_coCd.getValue() // 회사코드
    ,
    coClsCd: scwin.txtCoClsCd // 회사구분코드
    ,
    busiGrpCd: lc_busiGrpCd.getValue() // 사업자그룹코드
    ,
    pageNumber: scwin.txt_pageNumber // 페이지번호
    ,
    quantityOfRows: scwin.txt_quantityOfRows // 조회ROW수
    ,
    lowerDeptIncluYn: ds_search.get("lowerDeptIncluYn") // 하위부서포함여부
    ,
    acctDeptCd: ed_acctDeptCd.getValue() // 회계부서코드
    ,
    acctDeptNm: ed_acctDeptNm.getValue() // 회계부서명
    ,
    lowerAcctDeptIncluYn: ds_search.get("lowerAcctDeptIncluYn") // 하위회계부서포함여부
  };
  // ds_evid.DataID = "/ac.fi.taxbiz.vatctrl.RetrieveValueAddedTaxDataCMD.do" + strParam;
  // ds_evid.Reset();

  ds_search.setJSON(strParam);
  var dcJSON = ds_search.getJSON();
  console.log("  *** ds_search : " + JSON.stringify(dcJSON));
  $c.sbm.execute($p, sbm_search);
};

