//-------------------------------------------------------------------------
scwin.sbm_search_submitdone = async function (e) {
  console.log("▷ sbm_search_submitdone");
  if (e.responseJSON.resultDataSet[0].Code != 0) {
    // <!-- 증빙조회 DataSet -->
    // language=JavaScript for=tr_search event=OnFail()>
    //     cfShowError(tr_search);
    $c.gus.cfEnableKeyData($p);
    return;
  }
  if (e.responseJSON.GAUCE) {
    ds_evid.setJSON(e.responseJSON.GAUCE);
  }

  // language=JavaScript for=ds_evid event=OnLoadCompleted(rowCnt)>
  // var temp = ds_evid.RealCount(1, ds_evid.CountRow);
  // cfShowTotalRows(totalRows, temp);

  var rowCnt = ds_evid.getTotalRow();
  ed_totalRows.setValue(rowCnt);
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    //속도개선을 위한 추가조회(2013.03.20 이석건)
    $c.gus.cfDisableObjects($p, [btn_addSearch]);
    // bSearch2.style.display="none";
    ed_bSearch2.hide(); // 현재 데이터 조회중입니다. 잠시만 기다려 주세요.
  } else if (rowCnt > 999) {
    //조회 완료후 추가조회
    // bSearch2.style.display="none";
    ed_bSearch2.hide(); // 현재 데이터 조회중입니다. 잠시만 기다려 주세요.
    //f_Retrieve2();
  } else {
    // bSearch2.style.display="none";
    ed_bSearch2.hide(); // 현재 데이터 조회중입니다. 잠시만 기다려 주세요.
  }
  $c.gus.cfEnableObjects($p, [btn_addSearch]);

  // gr_evid.TitleHeight = "32";
};

