//-------------------------------------------------------------------------
// ds_evid_ondataload 정렬 / 셀 백그라운드 처리
//-------------------------------------------------------------------------
scwin.ds_evid_ondataload = function () {
  // <!-- 부가세목록 DataSet -->
  // <object id="ds_evid" classid="<%=DGauceCLSID.DATASET%>">
  // 	 <param name=SortExpr          value="+pchsEvidNo">

  ds_evid.sort("pchsEvidNo", 0); // 0:오름차순 , 1:내림차순

  // 삭제일 때 #CCCCCC (회색) 지정 : 증빙번호 ~ 수정일자 까지만
  for (i = 0; i < ds_evid.getTotalRow(); i++) {
    if (ds_evid.getCellData(i, "delYn") == "1") {
      gr_evid.setCellBackgroundColor(i, "pchsEvidNo", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "evidClsNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "zeroTaxClsNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "deductClsNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "slipAcctDeptNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "spplyDt", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "supplierCrn", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "supplierCrnNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "busiClsCd", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "spplyAmt", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "vat", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "hapgye", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "rmk", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "postDt", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "slipNo", "#CCCCCC");

      // console.log("111");
      // gr_evid.setCellClass(i, "slipNo", "");
      gr_evid.setCellColor(i, "pchsEvidNo", "black"); // 증빙번호 : 검정색
      gr_evid.setCellColor(i, "slipNo", "black"); // 전표번호 : 검정색
      gr_evid.setCellColor(i, "evidenceCnt", "black"); // 증빙갯수 : 검정색

      gr_evid.removeCellClass(i, "pchsEvidNo"); // 증빙번호 : class 제거
      gr_evid.removeCellClass(i, "slipNo"); // 전표번호 : class 제거
      gr_evid.removeCellClass(i, "evidenceCnt"); // 증빙갯수 : class 제거

      gr_evid.setCellBackgroundColor(i, "slipKndNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "opntAcctCd", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "opntAcctNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "subWkPlaceNo", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "vatDeclarAcctDeptNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "vatCrn", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "subWkPlaceNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "drawAcctDeptNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "drawEmpNm", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "slipDt", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "modDt", "#CCCCCC");
      gr_evid.setCellBackgroundColor(i, "taxnCls", "#CCCCCC"); // 과세구분 (히든)
    } else {
      gr_evid.setCellColor(i, "pchsEvidNo", "blue"); // 증빙번호 : 파랑색
      gr_evid.setCellColor(i, "slipNo", "blue"); // 전표번호 : 파랑색
      gr_evid.setCellColor(i, "evidenceCnt", "blue"); // 증빙갯수 : 파랑색

      gr_evid.setCellClass(i, "pchsEvidNo", "linktype"); // 증빙번호 : class - linktype
      gr_evid.setCellClass(i, "slipNo", "linktype"); // 전표번호 : class - linktype
      gr_evid.setCellClass(i, "evidenceCnt", "linktype"); // 증빙갯수 : class - linktype
    }
  } // end of for

  // 그리드 포커싱
  gr_evid.setFocusedCell(0, 1, false);
};

