//-------------------------------------------------------------------------
// 전표내역팝업 로딩
//-------------------------------------------------------------------------
scwin.gr_evid_oncellclick = function (rowIndex, columnIndex, columnId) {
  var Row = rowIndex;
  var Colid = columnId;
  // <!-- 전표번호,증빙구분클릭시  -->
  // language="javascript"  for=gr_evid event=OnClick(Row,Colid)>
  // 삭제된것은 popup 뜨지 않도록
  if (ds_evid.getCellData(Row, "delYn") == "0") {
    // 전표번호
    if (Colid == "slipNo" && Row >= 0) {
      $c.gus.cfShowSlipInfo($p, ds_evid.getCellData(Row, "slipNo")); // 전표내역 fi_201_04_02p
    }

    // 매입증빙번호
    if (Colid == "pchsEvidNo" && Row >= 0) {
      scwin.f_Evidence(Row); // 증빙내역 (부가세내역등록)  fi_401_01_09p
    }
    // 증빙갯수
    if (Colid == "evidenceCnt" && Row >= 0) {
      scwin.f_evidPopUp(); // 증빙등록조회  fi_403_01_02b
    }
  }
};

