//-------------------------------------------------------------------------
// 팝업결과
//  flag : 신규 추가. 어떤 팝업을 호출했는지 구분
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd, strNm, rtnList, flag) {
  console.log("=== f_resultPopEd (팝업결과)   flag [" + flag + "]  1:작성부서,2:부가세신고부서,3:사업자,4:전표종류,5:작성자,6:귀속부서)");
  console.log("   rtnList [" + rtnList + "]");

  // if (rtnList != null ) {
  // 	if (rtnList[0] == "N/A") {
  // 		return;
  // 	}
  // 	strCd.Text = rtnList[0];	// 코드
  // 	strNm.value = rtnList[1];	// 명
  // 	strCd.hidVal = rtnList[0];  // 히든값
  // }else{
  // 	strCd.Text = "";
  // 	strNm.value = "";
  // 	strCd.hidVal = "";
  // }
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      // 팝업 그냥 닫음
      // 히든값 분기처리
      switch (flag) {
        case '1':
          scwin.ed_drawAcctDeptCd_hidVal = "";
          break;
        // 작성부서
        case '2':
          scwin.ed_vatDeclarAcctDeptCd_hidVal = "";
          break;
        // 부가세신고부서
        case '3':
          scwin.ed_crn_hidVal = "";
          break;
        // 사업자번호
        case '4':
          scwin.ed_slipKndCd_hidVal = "";
          break;
        // 전표종류
        case '5':
          scwin.ed_drawEmpNo_hidVal = "";
          break;
        // 작성자
        case '6':
          scwin.ed_acctDeptCd_hidVal = "";
          break;
        // 귀속부서
        default:
          break;
      }
      return;
    }
    strCd.setValue(rtnList[0]); // 코드
    strNm.setValue(rtnList[1]); // 명

    // 히든값 분기처리
    switch (flag) {
      case '1':
        scwin.ed_drawAcctDeptCd_hidVal = rtnList[0];
        break;
      // 작성부서
      case '2':
        scwin.ed_vatDeclarAcctDeptCd_hidVal = rtnList[0];
        break;
      // 부가세신고부서
      case '3':
        scwin.ed_crn_hidVal = rtnList[0];
        break;
      // 사업자번호
      case '4':
        scwin.ed_slipKndCd_hidVal = rtnList[0];
        break;
      // 전표종류
      case '5':
        scwin.ed_drawEmpNo_hidVal = rtnList[0];
        break;
      // 작성자
      case '6':
        scwin.ed_acctDeptCd_hidVal = rtnList[0];
        break;
      // 귀속부서
      default:
        break;
    }
  } else {
    strCd.setValue("");
    strNm.setValue("");

    // 히든값 분기처리
    switch (flag) {
      case '1':
        scwin.ed_drawAcctDeptCd_hidVal = "";
        break;
      // 작성부서
      case '2':
        scwin.ed_vatDeclarAcctDeptCd_hidVal = "";
        break;
      // 부가세신고부서
      case '3':
        scwin.ed_crn_hidVal = "";
        break;
      // 사업자번호
      case '4':
        scwin.ed_slipKndCd_hidVal = "";
        break;
      // 전표종류
      case '5':
        scwin.ed_drawEmpNo_hidVal = "";
        break;
      // 작성자
      case '6':
        scwin.ed_acctDeptCd_hidVal = "";
        break;
      // 귀속부서
      default:
        break;
    }
  }
};

//-------------------------------------------------------------------------
// 팝업체크 - 코드값 변경시 자동검색  @@
//   flag : 팝업 플래그
//-------------------------------------------------------------------------
//   1:작성부서,2:부가세신고부서,3:사업자,4:전표종류,5:작성자,6:귀속부서
scwin.f_checkPopEd = function (strCd, strNm, flag) {
  console.log("===== f_checkPopEd (팝업체크 - 코드값 변경시 자동검색  srtCd[" + strCd.getValue() + "] strNm[" + strNm.getValue() + "] flag[" + flag + "]");

  // if (strCd.text.trim() == strCd.hidVal)
  // return;

  // strNm.value="";
  // strCd.hidVal="";
  // if(strCd.text.trim()!="") f_openPopUp(flag,'T');

  // if (strCd.getValue().trim() == strCd.hidVal) return; //return;
  if (flag == '1' && strCd.getValue().trim() == scwin.ed_drawAcctDeptCd_hidVal ||
  // 귀속부서
  flag == '2' && strCd.getValue().trim() == scwin.ed_vatDeclarAcctDeptCd_hidVal ||
  // 부가세신고부서
  flag == '3' && strCd.getValue().trim() == scwin.ed_crn_hidVal ||
  // 사업자번호
  flag == '4' && strCd.getValue().trim() == scwin.ed_slipKndCd_hidVal ||
  // 전표종류
  flag == '5' && strCd.getValue().trim() == scwin.ed_drawEmpNo_hidVal ||
  // 작성자
  flag == '6' && strCd.getValue().trim() == scwin.ed_acctDeptCd_hidVal // 귀속부서
  ) {
    // KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
    if (strCd.getValue() != "") return;
  }

  // strNm.value="";

  // 명 초기화 (한줄로 가능)
  strNm.setValue("");

  //	strCd.hidVal="";

  // 히든값 초기화
  switch (flag) {
    case '1':
      scwin.ed_drawAcctDeptCd_hidVal = "";
      break;
    // 귀속부서
    case '2':
      scwin.ed_vatDeclarAcctDeptCd_hidVal = "";
      break;
    // 부가세신고부서
    case '3':
      scwin.ed_crn_hidVal = "";
      break;
    // 사업자번호
    case '4':
      scwin.ed_slipKndCd_hidVal = "";
      break;
    // 전표종류
    case '5':
      scwin.ed_drawEmpNo_hidVal = "";
      break;
    // 작성자
    case '6':
      scwin.ed_acctDeptCd_hidVal = "";
      break;
    // 귀속부서

    default:
      break;
  }

  // if(strCd.text.trim()!="") {
  // 	f_openPopUp(flag,'T');

  if (strCd.getValue().trim() != "") {
    // 팝업 로딩
    scwin.f_openPopUp(flag, 'T');
  }
};

