//-------------------------------------------------------------------------
// 증빙삭제 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Delete = async function (e) {
  console.log("=== f_Delete 증빙삭제 버튼");

  // if(ds_evid.isUpdated==false){
  if (ds_evid.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_056, "데이타"));
    return;
  }

  // 이미 삭제된건 삭제하지 않는다.
  for (i = 0; i < ds_evid.getTotalRow(); i++) {
    // 가우스   :  0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
    // 웹스퀘어 :  R:초기상태, U:갱신, C:삽입, D:삭제, V:삽입 후 삭제

    // if(ds_evid.RowStatus(i)==3 && ds_evid.NameValue(i,"delYn")=="1"){
    if (ds_evid.getRowStatus(i) == "U" && ds_evid.getCellData(i, "delYn") == "1") {
      await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_041, "증빙번호[" + ds_evid.getCellData(i, "pchsEvidNo") + "]", "삭제처리를 "));
      return;
    }
  }

  // if(cfConfirmMsg(MSG_CM_CRM_008,Array("선택하신 증빙"))==true){
  let rtn = await $c.win.confirm($p, $c.data.getMessage($p, MSG_CM_CRM_008, "선택하신 증빙"));
  if (rtn) {
    // tr_delete.Action = "/ac.fi.taxbiz.vatctrl.DeleteValueAddedTaxContentsCMD.do";
    // tr_delete.Post();

    console.log("   -- -- 증빙삭제");
    sbm_delete.setAction = "/ac.fi.taxbiz.vatctrl.DeleteValueAddedTaxContentsCMD.do";
    $c.sbm.execute($p, sbm_delete);
  }
};

//-------------------------------------------------------------------------
// 증빙삭제취소 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_DeleteCancel = async function (e) {
  console.log("=== f_DeleteCancel 증빙삭제취소 버튼");

  // if(ds_evid.isUpdated==false){
  if (ds_evid.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_056, "데이타"));
    return;
  }

  // 삭제된건만 삭제취소를 한다.
  for (i = 1; i <= ds_evid.getTotalRow(); i++) {
    // 가우스   :  0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
    // 웹스퀘어 :  R:초기상태, U:갱신, C:삽입, D:삭제, V:삽입 후 삭제

    // if(ds_evid.RowStatus(i)==3 && ds_evid.NameValue(i,"delYn")=="0"){
    if (ds_evid.getRowStatus(i) == "U" && ds_evid.getCellData(i, "delYn") == "0") {
      await $c.gus.cfAlertMsg($p, "증빙번호[" + ds_evid.getCellData(i, "pchsEvidNo") + "]는 삭제된 증빙이 아닙니다.");
      return;
    }
  }

  // if(cfConfirmMsg("선택하신 증빙을 취소처리하시겠습니까?")==true){
  let rtn = await $c.win.confirm($p, "선택하신 증빙을 취소처리하시겠습니까?");
  if (rtn) {
    // tr_delete.Action = "/ac.fi.taxbiz.vatctrl.CancelDeleteValueAddedTaxContentsCMD.do";
    // tr_delete.Post();

    console.log("   -- -- 증빙삭제취소");
    sbm_delete.setAction = "/ac.fi.taxbiz.vatctrl.CancelDeleteValueAddedTaxContentsCMD.do";
    $c.sbm.execute($p, sbm_delete);
  }
};

